var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"가져왔습니다. 이사장님.","JPN":"お持ちしました、理事長。","ENG":"Here you are, Ms. Chairwoman.","TWN":"帶來了，理事長。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아 고마워요 루시드 선생님.","JPN":"ありがとうございます、ルシード先生。","ENG":"Oh, thank you, Ms. Lucid.","TWN":"謝謝你，露西德老師。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런데 나이엘 양의 자작 소설은 갑자기 왜…….","JPN":"ところで、ナイエルさんの自作小説はなぜ……","ENG":"But why did you want Naielle's novel, all of a sudden...?","TWN":"可是，為什麼突然提到奈爾的自創小說……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하, 그게…… 세상을 구하는데 이게 꼭 필요하거든요.","JPN":"あはは、それが……世界を救うために、これがどうしても必要なんです。","ENG":"Ah ha ha, well... we need this to save the world.","TWN":"哈哈哈，這個……拯救世界的時候，這個是必需的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"Excuse me...?","TWN":"嗯……？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"흠흠……!","JPN":"ごほん……！","ENG":"Ahem...!","TWN":"咳咳……！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그럼, 읽을게.","JPN":"じゃあ、読むわね。","ENG":"Then, I'll start reading it.","TWN":"那我就讀了喔。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아득한 고대로부터 이어져 온 의지가 내 영혼에 흐르고 있었다.","JPN":"遥か古代から受け継がれてきた意志が私の魂に流れている。","ENG":"Their wills, passed down from the start of time, flow in my soul.","TWN":"傳承於遙遠古代的意志在我的靈魂中流淌。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"모든 우주의 힘과…….","JPN":"全宇宙の力と……","ENG":"With the power of the entire universe...","TWN":"所有宇宙的力量……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우와아아아아악!!!!!","JPN":"わああああああっ！！","ENG":"AAAAAAAGH!!!","TWN":"嗚哇啊啊啊啊啊啊啊！！！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_02"},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"지금 이게 뭐 하자는 거야?! 그건 또 어디서 났어!","JPN":"な、何してるのよ！！　それ、どこで手に入れたの！？","ENG":"What are you doing?! Where did you get that?!","TWN":"現在這是幹什麼？！那又是從哪弄來的！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"나이엘 학생. 방금 이사장님께 모든 사정을 전해 들었어요.","JPN":"ナイエルさん。先ほど理事長にすべて聞きました。","ENG":"Naielle. The Chairwoman just told me what's going on.","TWN":"奈爾同學，剛剛聽理事長說了所有情況。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L21_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"봉사하실 때 아인과 츠바이에게 책 많이 읽어 주셨죠?","JPN":"ボランティアをしていた時、アインとツヴァイに本をたくさん読んであげましたよね。","ENG":"You used to read a lot of books to Eins and Zwei as volunteer work, correct?","TWN":"你在做志工服務時，經常給艾茵和茨粨讀故事書，對吧？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아이들이 가장 좋아하던 게 바로 그 책이었거든요.","JPN":"子どもたちがいちばん好きな本がこれだったんです。","ENG":"The children loved that book the most.","TWN":"孩子們最喜歡的就是那本書。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"나이엘 언니다! 언니~!!","JPN":"ナイエルお姉ちゃんだ！　お姉ちゃん～！！","ENG":"It's Naielle! Hi, Naielle!","TWN":"奈爾姊姊！姊姊～！！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"와~ 언니가 전설의 기사랑 싸우려나 봐!","JPN":"わあ～お姉ちゃん、伝説の騎士と戦うのかな？","ENG":"Wow! I think Naielle is going to fight the legendary knight!","TWN":"哇～姊姊好像要和傳說中的騎士戰鬥了！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"응원하고 있어요 학생. 부디 모두를 위해 세상을 구해주세요.","JPN":"応援していますよ。どうか、皆のために世界を救ってください。","ENG":"The students are cheering for you. Please, save the world for everyone.","TWN":"同學，我支持你，請為了大家拯救這個世界吧。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니 아니 잠깐!! 나 지금 상황이 하나도 이해 안 되거든?!","JPN":"ちょっとちょっと！！　この状況まったく意味がわからないんだけど！？","ENG":"Hey, w-wait!! I don't understand what's going on right now!","TWN":"喂喂，等等！！我現在完全搞不清楚狀況？！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"와 이리 부끄러워하는데? 애들 앞에선 잘 읽었다매?","JPN":"今さら何恥ずかしがっとんねん？　子どもたちの前ではすらすら読んでたんやろ？","ENG":"What are ya so embarrassed 'bout? Didn't ya read it out loud to the children?","TWN":"哇，怎麼這麼害羞？不是在孩子們面前讀得很好嗎？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니 그건 애들이니까 그렇지, 대중들한텐 무리라고!","JPN":"いや、それは子どもの前だからできたわけで、こんな大勢の前では無理よ！！","ENG":"That's because they were kids! It's embarrassing to read it to the public!","TWN":"那是因為他們是孩子，對別人我做不到！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"할 거야……. 생중계.","JPN":"やるよ……生中継。","ENG":"There will be... a livestream.","TWN":"要做的……現場直播。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"전 세계 사람들에게…… 나이엘의 모습.","JPN":"全世界に見せる……ナイエルの姿。","ENG":"A livestream of Naielle... to everyone in the world.","TWN":"向全世界的人們展示……奈爾的樣子。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미리네! 설마 이게 당신이 말한 작전이야?!","JPN":"マリ！　まさかあんたが言ってた作戦ってこれ！？","ENG":"Mi Rinae! Is this the plan you told me about?!","TWN":"宓璃奈！難道這就是你說的作戰計畫？！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래. 사람들의 무의식적인 CRF의 발현을 역으로 이용하는 기다.","JPN":"そうや。人々の無意識的なCRFの発現を逆利用するんや。","ENG":"Yup. We're gonna take advantage of the others' subconscious manifestation of CRF.","TWN":"對，就是要反過來利用人們無意識的CRF顯現。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니가 동경한 영웅의 모습으로, 사람들에게 인식 개변을 일으키는 거지.","JPN":"あんたが憧れてた英雄の姿で、人々の認識を改変させる。","ENG":"We're gonna change their perception with the appearance of the hero you admire.","TWN":"以你所仰慕的英雄形象，改變人們的認知。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"사람들의 부정적인 감정으로 폭주한 거라면, 너의 모습을 통해 긍정적인 감정을 쌓아 오버로드를 정상화하는 작전이다.","JPN":"皆はネガティブな感情のせいで暴走してるんや。だからあんたの姿を見せてポジティブな感情を呼び起こし、オーバーロードを正常化するっちゅう作戦や。","ENG":"If Overlord is goin' berserk because of negative emotions, this plan is to stabilize it with positive emotions through ya.","TWN":"如果是因為人們的負面情緒而暴走的話，作戰計畫記受透過你的形象積累正面情緒來使超載恢復正常。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"이만하면 쉽게 설명한 거 같다. 이해됐제?!","JPN":"なるたけ簡単に説明したけど、わかったか？","ENG":"I think that was pretty easy to understand. Ya got all that?!","TWN":"我覺得已經解釋得很清楚了，明白了嗎？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니 됐겠냐고!","JPN":"わかるわけないでしょう！！","ENG":"What do you think?!","TWN":"不是說不行嗎！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"마! 괘안타, 괘안타!","JPN":"まあまあ、大丈夫大丈夫！","ENG":"C'mon! It's gon' be aight!","TWN":"喂！沒事，沒事！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"프로레슬링 아나? 그것처럼 다 각본 짜놓고 하는 거로 생각하면 된다.","JPN":"プロレスって知ってるか？　あれと一緒や。全部筋書きどおりにやればええんや。","ENG":"Dontcha know professional wrestlin'? Think of this bein' scripted like that.","TWN":"你知道職業摔角嗎？你就當作都是按劇本進行的就好。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아까는 플레이어들하고 카운터즈 레거시까지 다 구하겠다믄서, 설마 겁먹읏나?","JPN":"プレイヤーもカウンターズ・レガシーも全部救ってみせるとか大口叩いとったのに、びびってるんか？","ENG":"Didn't ya say ya wanted to save the players and Counters Legacy? Are ya scared?","TWN":"剛才還說要和玩家們一起拯救制裁者的遺產，難道現在害怕了嗎？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"완성했어…… 모델링.","JPN":"完成した……モデリング。","ENG":"It's finished... the modeling.","TWN":"完成了……設計。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"코스튬……. 인류의 영웅.","JPN":"コスチューム……人類の英雄。","ENG":"The costume for... the hero of humanity.","TWN":"造型……人類的英雄。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이 모습이…… 나라고?","JPN":"こ、これが……私？","ENG":"Th-this is... me?","TWN":"這，這……是我嗎？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"오~ 멋지게 잘 뽑혔네! 소설에 나온 거랑 찰떡 아이가!","JPN":"おお～いいできやな。小説から飛び出してきたんじゃないかと思うくらいぴったりや！","ENG":"Ooh! Ain't that a cool outfit! It looks just like the one from the story!","TWN":"喔～畫得真不錯！和小說裡的一模一樣啊！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그런가……? 머, 멋있기는 하지만…….","JPN":"そ、そう……？　た、確かに格好いいけど……","ENG":"R-really...? I guess it's cool, but...","TWN":"是，是嗎……？是，是很帥沒錯……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 까짓거 하면 되잖아! 근데 생중계는 어떻게 하려고?","JPN":"ふん！　やればいいんでしょやれば！　でも生中継はどうするの？","ENG":"Hmph! Fine, I'll do it! But what about the livestream?","TWN":"哼！不管了！不過現場直播要怎麼做？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그건 저한테 맡겨주세요. 카운터즈 레거시를 되돌릴 수 있다면 뭐든 하겠어요!","JPN":"それは私に任せてください。カウンターズ・レガシーを元に戻せるなら何でもやります！","ENG":"Leave that to me. I'll do anything to save Counters Legacy!","TWN":"這個就交給我吧。如果能找回制裁者的遺產，我什麼都願意做！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"하트베리 분들이라면 분명 도움이 될 수 있을 거라 생각해서 모셔 왔어요!","JPN":"ハートベリーの皆さんに協力してもらえると思って、連れてきました！","ENG":"I brought HRT Berry here because I thought they would be able to help us!","TWN":"我請來了愛心莓果的成員，因為我覺得她們一定能幫上忙！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"아, 안녕하세요 여러분. 저희들의 도움이 필요하다고 하셔서 왔어요.","JPN":"こ、こんにちは皆さん。私たちの助けが必要だと言われて来ました……","ENG":"H-hello, everyone. We came after hearing that you needed our help.","TWN":"大，大家好。聽說你們需要我們的幫忙，所以我們來了。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L17_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"시청자들을 끌어모으면 된다는 거지? 우리도 협조할게!","JPN":"アタシたちが視聴者をたくさん集めてくればいいのね？　協力するわ！","ENG":"All we need to do is gather a lot of viewers, right? We can do that!","TWN":"只要能吸引觀眾就行了吧？我們也會配合的！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"가람아…….","JPN":"ヒカリ……","ENG":"Garam...","TWN":"嘉蘭……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 땅꼬마도 나름대로 쓸모가 있네?","JPN":"へえ、チビもそれなりに仕事ができるじゃない。","ENG":"Haha! I guess pipsqueak is finally being useful.","TWN":"哈哈，矮冬瓜也有點用處嘛？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……미안해요 학생. 전 선생 실격이에요.","JPN":"……ごめんなさい。私は教師失格です。","ENG":"...I'm sorry, Naielle. Guess I'm not fit to be a teacher.","TWN":"……對不起，我這個老師不合格。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"이에 대한 책임은 꼭 지겠어요. 정말 죄송해요.","JPN":"この責任は必ず取ります。本当にごめんなさい。","ENG":"I'll take full responsibility for this. I really apologize.","TWN":"我一定會對此負責的，真的很抱歉。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……사과는 유저들한테나 하셔. 난 쿨해서 이미 다 잊었거든?","JPN":"……それはユーザーに言えば？　私はクールだからもう全部忘れちゃったの。","ENG":"...Make your apology to the players. I'm cool, so I've already forgotten about it, okay?","TWN":"……道歉就留給玩家吧，我早就忘記了。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나중에 다 해결하면, 그때 또 보자고.","JPN":"事態が全部解決したら、ゆっくり話しましょ。","ENG":"We can talk about it once this is all settled.","TWN":"等我都解決後再見吧。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"학생…….","JPN":"ナイエルさん……","ENG":"Naielle...","TWN":"奈爾……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"좋아. 그럼 로그인 시켜줘!","JPN":"よし。じゃ、ログインさせて！","ENG":"All right. Log me in!","TWN":"好，讓我登入吧！"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"평소와는 완전히 분위기가 달라.","JPN":"いつもとはまったく雰囲気が違う。","ENG":"It feels completely different from what it used to look like.","TWN":"和平時的氛圍完全不同。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"내가 해내지 못하면 분명 이면세계가 되는 건 시간문제겠지.","JPN":"私が失敗したら裏世界になるのは時間の問題……","ENG":"If I fail, it will only be a matter of time before this place really turns into the Counterside.","TWN":"如果我做不到，異界的出現只是時間問題。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"여러분 안녕하세요. 하트베리의 미야입니다.","JPN":"皆さん、こんにちは。ハートベリーのミヤです。","ENG":"Hi, everyone. This is Miya from HRT Berry.","TWN":"大家好，我是愛心莓果的米婭。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"오늘은 카운터즈 레거시 사상 최대 규모 컨텐츠. 무한 디펜스를 진행할 거에요.","JPN":"今日はカウンターズ・レガシー史上最大規模のコンテンツ。無限ディフェンスをお届けします。","ENG":"Today, we're going to show you Counters Legacy's biggest update in history, the Infinite Defense.","TWN":"今天將進行制裁者的遺產史上最大規模的內容——無限守衛。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color>읭 뭐임? 오늘 원래 방송 날이었나?\\n<color=#ffd34c>■■■</color>무한 디펜스? 아까부터 계속 접속 못한 이유가 이거였어?","JPN":"<color=#ffd34c>■■■</color>なんだ？　今日配信の日だったっけ？\\n<color=#ffd34c>■■■</color>無限ディフェンス？　さっきからログイン失敗してたのってこれのせい？","ENG":"<color=#ffd34c>■■■</color> Huh? Was there a livestream scheduled today?\\n<color=#ffd34c>■■■</color> Infinite Defense? Is that why I couldn't log in all this time?","TWN":"<color=#ffd34c>■■■</color>這是什麼？今天怎麼有直播？\\n<color=#ffd34c>■■■</color>無限守衛？這是就不能登入的原因嗎？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"참여자는 카운터즈 레거시의 랭커! 나이엘 블루스틸~!","JPN":"参加者はカウンターズ・レガシーのランカー、ナイエル・ブルースチール！","ENG":"Our contender is Counters Legacy's ranker, Naielle Bluesteel!","TWN":"參加者是制裁者的遺產的前段班！奈爾·布魯斯提爾～！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L42_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"랭킹 2위의 유쾌한 반란! 과연 그녀는 이번 퀘스트로 1위를 차지할 수 있을 것인가!","JPN":"ランキング2位の痛快な反乱！　果たして彼女はこのクエストで1位を手にすることができるでしょうか！","ENG":"Rank number 2's cheerful rebellion! Will she be able to take the number 1 place with this quest?","TWN":"排名第二的反擊！她能透過這次任務奪得第一名嗎！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color>오오! 나 저 사람 알아! 뭔가 했더니 이걸 준비했던 거야?\\n<color=#ffd34c>■■■</color>못 보던 코스튬인데? 단단히 준비하고 왔구만? ","JPN":"<color=#ffd34c>■■■</color>おお！　あの人知ってる！　何かあると思ったらこれを準備してたのか！\\n<color=#ffd34c>■■■</color>初めてみるコスチュームだ！　めっちゃ気合入ってるな～ ","ENG":"<color=#ffd34c>■■■</color> Oh! I know who she is! Is this what they've been preparing?\\n<color=#ffd34c>■■■</color> I haven't seen her wear that costume before. Looks like she prepared a lot for this. ","TWN":"<color=#ffd34c>■■■</color>喔喔！我知道她！還以為是什麼，原來是這個？\\n<color=#ffd34c>■■■</color>沒看過的造型欸？看來是有備而來喔？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"반응이 좋아. 시청자 수가 엄청나게 늘어나고 있어.","JPN":"反応がいい。視聴者数がすごい勢いで増えてる。","ENG":"The responses are looking good. The number of viewers is increasing tremendously.","TWN":"直播反應很好，觀眾人數在急劇增加。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"긴장 풀면 안 된데이. 이건 엄연히 침식현상이니께.","JPN":"気を抜くな。これは紛れもない侵食現象や。","ENG":"Ya better not let your guard down. This is still a Counterside Effect.","TWN":"不能放鬆警惕，這可是貨真價實的侵蝕現象。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"아앗! 신호도 없이 몬스터들의 출격!","JPN":"ああっ！　何の予告もなくモンスターの出撃！","ENG":"Oh! The monsters have started to rush out without any notice!","TWN":"啊啊！怪物們毫無預警地出擊了！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"자, 잠깐! 이 녀석들 다짜고짜 전부 3종 침식체잖아?!","JPN":"ちょ、ちょっと！　いきなり全部第3種侵食体！？","ENG":"H-hold on! All of them are Category 3 C.O.s!","TWN":"等，等一下！這些傢伙全都是3類侵蝕體？！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"선배! 저희가 도우러 왔어요!","JPN":"先輩！　助けに来ました！","ENG":"Naielle! We're here to help!","TWN":"前輩！我們來幫忙了！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하핫! 영웅에겐 언제나 훌륭한 사이드킥이 있어 줘야 하지 않겠어?","JPN":"ははっ！　英雄には優秀なサイドキックがつきものだろ？","ENG":"Haha! Doesn't a hero need to have great sidekicks?","TWN":"哈哈！英雄總是需要出色的助手，不是嗎？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저희도 각오하고 온 거예요 선배! 저흰 한 파티잖아요!","JPN":"あたしたちも覚悟してきました、先輩！　だってあたしたちは同じパーティーですから！","ENG":"We've made up our minds, Naielle! We're a party, remember?","TWN":"我們也是做好了心理準備來的，前輩！我們是一隊的嘛！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"자, 잠깐! 아카데미 학생들은 접속 못 하게 한 거 아니었니?","JPN":"え、ええっ！？　アカデミーの生徒はログインを遮断しているはず……！","ENG":"W-wait! Weren't the Academy students blocked from accessing the game?","TWN":"等，等一下！不是說好了不讓學院的學生登入的嗎？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하하! 이럴 때를 대비해서 기척 완벽 차단! 도구를 만들었거든요.","JPN":"はは！　こういう時に備えて、気配を完璧に消す道具を作っておいたんだ！","ENG":"Haha! That's why I made this in case something like this happened! The perfect stealth tool!","TWN":"哈哈！為了應付這種情況，我製作了完美隔離氣息的工具。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이디스! 어서 로그아웃시키렴!","JPN":"イーディス！　早く強制ログアウトさせて！","ENG":"Edith! Log them out, now!","TWN":"伊蒂絲！快點讓她登出！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"아직 오버로드의 시스템 장악률이 더 높아서 무리에요.","JPN":"まだオーバーロードのシステム掌握率のほうが高くて無理。","ENG":"Overlord's system takeover rate is much higher, so I can't.","TWN":"還是因為超載的系統掌控率更高，所以很困難。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L15_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"일단 가람 선생님과 시스템을 해킹해 보고 있어요. 조금만 기다려 주세요.","JPN":"とりあえず、ヒカリ先生と一緒にシステムハッキングを試してる。もうちょっと待って。","ENG":"Ms. Seo and I are trying to hack the system. Give us a minute.","TWN":"我正在和嘉蘭老師一起嘗試破解系統，請稍等一下。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"꼬맹이들. 이건 더 이상 게임이 아냐. 각오는 됐어?","JPN":"チビたち、これはもうゲームじゃないよ。覚悟はできてる？","ENG":"You rascals. This isn't just a game anymore. Are you sure you're up for this?","TWN":"小鬼們，這已經不再是遊戲了。做好覺悟了嗎？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L20_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"저흰 언제나 준비 되어있어요 선배!","JPN":"私たちはいつだって準備オーケーですよ、先輩！","ENG":"We're always ready, Naielle!","TWN":"我們準備好了，前輩！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어서 가요. 지금까지의 수련의 성과를 보여드릴게요!","JPN":"早く行きましょう。今までの修行の成果、お見せします！","ENG":"Let's go. It's time to show the results of our training!","TWN":"快走吧，讓我展示一下到目前為止的修煉成果！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_LEGACY_NULL_NULL","text":{"KOREA":"좋아. 그럼 가보자고!","JPN":"よし、じゃあ行くよ！","ENG":"Okay. Let's do this!","TWN":"好，那就出發吧！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_CA_TWINTAIL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};